import re

with open(locals()['var_function-call-4974488808225168135'], 'r') as f:
    patents = json.load(f)

h2_count = 0
countries = {}

months_h2 = ['Jul', 'Aug', 'Sep', 'Oct', 'Nov', 'Dec', 
             'July', 'August', 'September', 'October', 'November', 'December']

for p in patents:
    g_date = p.get('grant_date', '')
    if '2019' in g_date:
        is_h2 = False
        for m in months_h2:
            if m in g_date:
                is_h2 = True
                break

        if is_h2:
            h2_count += 1
            p_info = p.get('Patents_info', '')
            # Extract country rough guess (word after "from" or "In")
            # Or just look for country codes
            found_cc = []
            for cc in ['DE', 'US', 'RU', 'EP', 'CN', 'JP', 'KR', 'DK', 'ES']:
                if cc in p_info:
                    found_cc.append(cc)

            # Look for specific phrases
            origin = "Unknown"
            m = re.search(r'\bfrom ([A-Z]{2})\b', p_info)
            if m:
                origin = m.group(1)
            else:
                m = re.search(r'\bIn ([A-Z]{2})\b', p_info)
                if m:
                    origin = m.group(1)

            countries[origin] = countries.get(origin, 0) + 1

print("__RESULT__:")
print(json.dumps({"h2_count": h2_count, "countries": countries}))
"}

{"code":"import json
import re
from collections import defaultdict

# Load data
with open(locals()['var_function-call-4974488808225168135'], 'r') as f:
    patents = json.load(f)

with open(locals()['var_function-call-4381654191407381320'], 'r') as f:
    titles_list = json.load(f)

cpc_titles = {item['symbol']: item['titleFull'] for item in titles_list}

def parse_year(date_str):
    match = re.search(r'\b(19|20)\d{2}\b', date_str)
    if match:
        return int(match.group(0))
    return None

def is_h2_2019(date_str):
    if not date_str: return False
    if '2019' not in date_str: return False
    months_h2 = ['Jul', 'Aug', 'Sep', 'Oct', 'Nov', 'Dec', 
                 'July', 'August', 'September', 'October', 'November', 'December']
    for m in months_h2:
        if m in date_str:
            return True
    return False

filtered_patents = []
for p in patents:
    if is_h2_2019(p.get('grant_date', '')):
        p_info = p.get('Patents_info', '')
        # Check for Germany
        if re.search(r'\bDE\b', p_info) or "Germany" in p_info or "German" in p_info:
            # Double check to avoid false positives if possible
            # But \bDE\b is quite specific in this context

            f_year = parse_year(p.get('filing_date', ''))
            if f_year:
                filtered_patents.append({
                    'year': f_year,
                    'cpc': p.get('cpc', '[]')
                })

# Aggregation
counts = defaultdict(lambda: defaultdict(int)) # code -> year -> count
all_years = set()

for p in filtered_patents:
    f_year = p['year']
    try:
        cpc_data = json.loads(p['cpc'])
    except:
        continue

    unique_codes = set()
    for item in cpc_data:
        code = item.get('code', '')
        if len(code) >= 3:
            cls = code[:3]
            unique_codes.add(cls)

    for cls in unique_codes:
        counts[cls][f_year] += 1
        all_years.add(f_year)

# EMA Calculation
alpha = 0.1
results = []

if not all_years:
    print("__RESULT__:")
    print("[]")
    exit()

min_y = min(all_years)
max_y = max(all_years)
timeline = range(min_y, max_y + 1)

for code, year_counts in counts.items():
    current_ema = 0
    max_ema = -1.0
    best_year = -1

    # Initialize EMA
    # If using recursive: S_t = alpha*Y_t + (1-alpha)*S_{t-1}
    # For t=0 (min_y), S_0 = Y_0 ?
    # Let's use that.

    first = True

    for y in timeline:
        cnt = year_counts.get(y, 0)
        if first:
            current_ema = cnt
            first = False
        else:
            current_ema = alpha * cnt + (1 - alpha) * current_ema

        if current_ema > max_ema:
            max_ema = current_ema
            best_year = y

    results.append({
        "full_title": cpc_titles.get(code, "N/A"),
        "cpc_group_code": code,
        "best_year": best_year,
        "max_ema": max_ema
    })

results.sort(key=lambda x: x['max_ema'], reverse=True)
top_results = results[:10] # Top 10

print("__RESULT__:")
print(json.dumps(top_results))
"}

